1	//! Term representation — what all data is made of.
2	//!
3	//! A term is a single 64-bit machine word with low-bit tagging.
4	//! Immediates (small integers, atoms, pids, nil) fit entirely in
5	//! the word. Boxed values (tuples, lists, binaries, floats, big
6	//! integers, closures, maps, references) are tagged pointers into
7	//! the process-local heap.
8	pub mod binary;
9	pub mod boxed;
10	pub mod compare;
11	
12	use crate::atom::Atom;
13	
14	const TAG_BITS: u32 = 3;
15	const TAG_MASK: u64 = (1 << TAG_BITS) - 1;
16	const PAYLOAD_BITS: u32 = u64::BITS - TAG_BITS;
17	
18	const SMALL_INT_TAG: u64 = 0b000;
19	const ATOM_TAG: u64 = 0b001;
20	const PID_TAG: u64 = 0b010;
21	const NIL_TAG: u64 = 0b011;
22	const BOXED_TAG: u64 = 0b100;
23	const LIST_TAG: u64 = 0b101;
24	
25	const SMALL_INT_MIN: i64 = -(1_i64 << (PAYLOAD_BITS - 1));
26	const SMALL_INT_MAX: i64 = (1_i64 << (PAYLOAD_BITS - 1)) - 1;
27	const UNSIGNED_PAYLOAD_MAX: u64 = (1_u64 << PAYLOAD_BITS) - 1;
28	
29	/// Primary tag for a [`Term`].
30	#[derive(Copy, Clone, Debug, Eq, PartialEq)]
31	pub enum Tag {
32	    /// Signed small integer stored directly in the term payload.
33	    SmallInt,
34	    /// Atom index stored directly in the term payload.
35	    Atom,
36	    /// Local process identifier stored directly in the term payload.
37	    Pid,
38	    /// Distinguished empty list value.
39	    Nil,
40	    /// Boxed heap pointer tag, reserved for boxed values.
41	    Boxed,
42	    /// List heap pointer tag, reserved for cons cells.
43	    List,
44	}
45	
46	/// A single tagged BEAM term word.
47	///
48	/// The low three bits hold the primary tag. The remaining bits hold immediate
49	/// payload data or, for future boxed/list terms, tagged heap pointer data.
50	#[derive(Copy, Clone, Debug, Eq, PartialEq)]
51	pub struct Term(u64);
52	
53	impl Term {
54	    /// Distinguished empty list / nil value.
55	    pub const NIL: Self = Self(NIL_TAG);
56	
57	    /// Minimum integer that can be represented as an immediate small integer.
58	    pub const SMALL_INT_MIN: i64 = SMALL_INT_MIN;
59	
60	    /// Maximum integer that can be represented as an immediate small integer.
61	    pub const SMALL_INT_MAX: i64 = SMALL_INT_MAX;
62	
63	    /// Maximum local pid payload that can be represented as an immediate pid.
64	    pub const PID_MAX: u64 = UNSIGNED_PAYLOAD_MAX;
65	
66	    /// Creates a small integer term.
67	    ///
68	    /// Panics when `value` is outside the immediate small integer range. Use
69	    /// [`Term::try_small_int`] when handling runtime arithmetic that may need
70	    /// big integer boxing in a later implementation phase.
71	    pub const fn small_int(value: i64) -> Self {
72	        match Self::try_small_int(value) {
73	            Some(term) => term,
74	            None => panic!("small integer value is outside the immediate range"),
75	        }
76	    }
77	
78	    /// Attempts to create a small integer term without truncating out-of-range
79	    /// values.
80	    pub const fn try_small_int(value: i64) -> Option<Self> {
81	        if value < SMALL_INT_MIN || value > SMALL_INT_MAX {
82	            None
83	        } else {
84	            Some(Self(((value as u64) << TAG_BITS) | SMALL_INT_TAG))
85	        }
86	    }
87	
88	    /// Creates an atom term.
89	    pub const fn atom(atom: Atom) -> Self {
90	        Self(((atom.index() as u64) << TAG_BITS) | ATOM_TAG)
91	    }
92	
93	    /// Creates an immediate local pid term.
94	    ///
95	    /// Panics when `pid` does not fit in the immediate pid payload. Use
96	    /// [`Term::try_pid`] for fallible construction from arbitrary `u64` values.
97	    pub const fn pid(pid: u64) -> Self {
98	        match Self::try_pid(pid) {
99	            Some(term) => term,
100	            None => panic!("pid value is outside the immediate range"),
101	        }
102	    }
103	
104	    /// Attempts to create an immediate local pid term without truncating high
105	    /// bits.
106	    pub const fn try_pid(pid: u64) -> Option<Self> {
107	        if pid > UNSIGNED_PAYLOAD_MAX {
108	            None
109	        } else {
110	            Some(Self((pid << TAG_BITS) | PID_TAG))
111	        }
112	    }
113	
114	    /// Returns the primary tag for this term.
115	    pub const fn tag(self) -> Tag {
116	        match self.0 & TAG_MASK {
117	            SMALL_INT_TAG => Tag::SmallInt,
118	            ATOM_TAG => Tag::Atom,
119	            PID_TAG => Tag::Pid,
120	            NIL_TAG => {
121	                if self.0 == Self::NIL.0 {
122	                    Tag::Nil
123	                } else {
124	                    Tag::Boxed
125	                }
126	            }
127	            BOXED_TAG => Tag::Boxed,
128	            LIST_TAG => Tag::List,
129	            _ => Tag::Boxed,
130	        }
131	    }
132	
133	    /// Returns `true` when this term is an immediate small integer.
134	    pub const fn is_small_int(self) -> bool {
135	        matches!(self.tag(), Tag::SmallInt)
136	    }
137	
138	    /// Returns `true` when this term is an immediate atom.
139	    pub const fn is_atom(self) -> bool {
140	        matches!(self.tag(), Tag::Atom)
141	    }
142	
143	    /// Returns `true` when this term is an immediate pid.
144	    pub const fn is_pid(self) -> bool {
145	        matches!(self.tag(), Tag::Pid)
146	    }
147	
148	    /// Returns `true` only for the canonical empty list / nil value.
149	    pub const fn is_nil(self) -> bool {
150	        self.0 == Self::NIL.0
151	    }
152	
153	    /// Returns `true` when this term carries the boxed heap pointer tag.
154	    pub const fn is_boxed(self) -> bool {
155	        matches!(self.tag(), Tag::Boxed)
156	    }
157	
158	    /// Returns `true` when this term carries the list heap pointer tag.
159	    pub const fn is_list(self) -> bool {
160	        matches!(self.tag(), Tag::List)
161	    }
162	
163	    /// Decodes this term as a small integer, if it is one.
164	    pub const fn as_small_int(self) -> Option<i64> {
165	        if self.is_small_int() {
166	            Some((self.0 as i64) >> TAG_BITS)
167	        } else {
168	            None
169	        }
170	    }
171	
172	    /// Decodes this term as an atom, if it is one.
173	    pub const fn as_atom(self) -> Option<Atom> {
174	        if self.is_atom() {
175	            Some(Atom::from_index((self.0 >> TAG_BITS) as u32))
176	        } else {
177	            None
178	        }
179	    }
180	
181	    /// Decodes this term as local pid data, if it is one.
182	    pub const fn as_pid(self) -> Option<u64> {
183	        if self.is_pid() {
184	            Some(self.0 >> TAG_BITS)
185	        } else {
186	            None
187	        }
188	    }
189	}
190	
191	#[cfg(test)]
192	mod tests {
193	    use super::{Tag, Term};
194	    use crate::atom::Atom;
195	
196	    #[test]
197	    fn term_is_one_machine_word_with_private_tagged_value() {
198	        assert_eq!(std::mem::size_of::<Term>(), 8);
199	        assert_eq!(Term::small_int(1).tag(), Tag::SmallInt);
200	    }
201	
202	    #[test]
203	    fn small_int_round_trips_and_preserves_sign() {
204	        for value in [0, 42, -1, Term::SMALL_INT_MAX, Term::SMALL_INT_MIN] {
205	            let term = Term::small_int(value);
206	
207	            assert_eq!(term.as_small_int(), Some(value));
208	            assert!(term.is_small_int());
209	            assert_eq!(term.tag(), Tag::SmallInt);
210	        }
211	    }
212	
213	    #[test]
214	    fn small_int_checked_constructor_rejects_out_of_range_values() {
215	        assert_eq!(Term::try_small_int(Term::SMALL_INT_MAX + 1), None);
216	        assert_eq!(Term::try_small_int(Term::SMALL_INT_MIN - 1), None);
217	    }
218	
219	    #[test]
220	    fn atom_round_trips_without_becoming_nil() {
221	        for atom in [Atom::OK, Atom::ERROR, Atom::NIL] {
222	            let term = Term::atom(atom);
223	
224	            assert_eq!(term.as_atom(), Some(atom));
225	            assert!(term.is_atom());
226	            assert_eq!(term.tag(), Tag::Atom);
227	            assert!(!term.is_small_int());
228	            assert!(!term.is_pid());
229	            assert!(!term.is_nil());
230	        }
231	    }
232	
233	    #[test]
234	    fn pid_round_trips() {
235	        for pid in [0, 12_345, Term::PID_MAX] {
236	            let term = Term::pid(pid);
237	
238	            assert_eq!(term.as_pid(), Some(pid));
239	            assert!(term.is_pid());
240	            assert_eq!(term.tag(), Tag::Pid);
241	            assert!(!term.is_small_int());
242	            assert!(!term.is_atom());
243	        }
244	    }
245	
246	    #[test]
247	    fn pid_checked_constructor_rejects_out_of_range_values() {
248	        assert_eq!(Term::try_pid(Term::PID_MAX + 1), None);
249	    }
250	
251	    #[test]
252	    fn nil_is_distinguished_from_integer_atom_and_pid_values() {
253	        assert!(Term::NIL.is_nil());
254	        assert_eq!(Term::NIL.tag(), Tag::Nil);
255	        assert!(!Term::small_int(0).is_nil());
256	        assert!(!Term::atom(Atom::NIL).is_nil());
257	        assert!(!Term::pid(0).is_nil());
258	        assert_ne!(Term::NIL, Term::small_int(0));
259	    }
260	
261	    #[test]
262	    fn tag_dispatch_and_predicates_agree_for_immediates() {
263	        let terms = [
264	            (Term::small_int(1), Tag::SmallInt),
265	            (Term::atom(Atom::OK), Tag::Atom),
266	            (Term::pid(1), Tag::Pid),
267	            (Term::NIL, Tag::Nil),
268	        ];
269	
270	        for (term, tag) in terms {
271	            assert_eq!(term.tag(), tag);
272	            assert_eq!(term.is_small_int(), tag == Tag::SmallInt);
273	            assert_eq!(term.is_atom(), tag == Tag::Atom);
274	            assert_eq!(term.is_pid(), tag == Tag::Pid);
275	            assert_eq!(term.is_nil(), tag == Tag::Nil);
276	            assert_eq!(term.is_boxed(), tag == Tag::Boxed);
277	            assert_eq!(term.is_list(), tag == Tag::List);
278	        }
279	    }
280	
281	    #[test]
282	    fn cross_type_extractors_return_none() {
283	        let integer = Term::small_int(42);
284	        let atom = Term::atom(Atom::OK);
285	        let pid = Term::pid(12_345);
286	        let nil = Term::NIL;
287	
288	        assert_eq!(integer.as_atom(), None);
289	        assert_eq!(integer.as_pid(), None);
290	        assert_eq!(atom.as_small_int(), None);
291	        assert_eq!(atom.as_pid(), None);
292	        assert_eq!(pid.as_small_int(), None);
293	        assert_eq!(pid.as_atom(), None);
294	        assert_eq!(nil.as_small_int(), None);
295	        assert_eq!(nil.as_atom(), None);
296	        assert_eq!(nil.as_pid(), None);
297	    }
298	}

1	//! Global atom table — the shared vocabulary of the running system.
2	//!
3	//! Every name (module names, function names, atoms like `ok` and `error`)
4	//! is interned here exactly once. Atoms are compared by index, not by
5	//! string content, making pattern matching cheap.
6	pub mod table;
7	
8	/// Interned atom handle.
9	///
10	/// Atoms are compared by their table index. The raw index is intentionally
11	/// private to the crate so public APIs can pass atoms around without exposing
12	/// the table representation.
13	#[derive(Copy, Clone, Debug, Eq, PartialEq, Hash)]
14	pub struct Atom(u32);
15	
16	impl Atom {
17	    /// Common atom `ok`.
18	    pub const OK: Self = Self(0);
19	
20	    /// Common atom `error`.
21	    pub const ERROR: Self = Self(1);
22	
23	    /// Common atom `true`.
24	    pub const TRUE: Self = Self(2);
25	
26	    /// Common atom `false`.
27	    pub const FALSE: Self = Self(3);
28	
29	    /// Common atom `nil`.
30	    pub const NIL: Self = Self(4);
31	
32	    pub(crate) const fn from_index(index: u32) -> Self {
33	        Self(index)
34	    }
35	
36	    pub(crate) const fn index(self) -> u32 {
37	        self.0
38	    }
39	}

